-- Modify "outsourcing_order_items" table
ALTER TABLE "outsourcing_order_items" ADD CONSTRAINT "outsourcing_order_items_material_id_positive" CHECK ((material_id IS NULL) OR (material_id > 0)), ADD CONSTRAINT "outsourcing_order_items_product_id_positive" CHECK ((product_id IS NULL) OR (product_id > 0)), ADD CONSTRAINT "outsourcing_order_items_subject_exactly_one" CHECK ((((subject_type)::text = 'PRODUCT'::text) AND (product_id IS NOT NULL) AND (material_id IS NULL)) OR (((subject_type)::text = 'MATERIAL'::text) AND (product_id IS NULL) AND (material_id IS NOT NULL))), ADD CONSTRAINT "outsourcing_order_items_subject_type_allowed" CHECK ((subject_type)::text = ANY ((ARRAY['PRODUCT'::character varying, 'MATERIAL'::character varying])::text[])), ALTER COLUMN "product_id" DROP NOT NULL, ADD COLUMN "subject_type" character varying NOT NULL DEFAULT 'PRODUCT', ADD COLUMN "material_code_snapshot" character varying NULL, ADD COLUMN "material_name_snapshot" character varying NULL, ADD COLUMN "material_id" bigint NULL, ADD CONSTRAINT "outsourcing_order_items_materials_outsourcing_order_items" FOREIGN KEY ("material_id") REFERENCES "materials" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION;
